(31, 'default', 'Contact', 'contact', '{\"title\":\"Contact Us\",\"phone_no\":\"+05555555555\",\"email\":\"contact@qunzo.com\",\"address\":\"2972 Westheimer Rd. Santa Ana, Illinois 85486\",\"meta_keywords\":\"contact us, email\",\"meta_description\":\"Contact\",\"phone_icon\":\"global\\/uploads\\/images\\/ct86uRaB6LjvH9O3ZwuS.svg\",\"email_icon\":\"global\\/uploads\\/images\\/iRMVI9m4woOAUNfoJhkB.svg\",\"address_icon\":\"global\\/uploads\\/images\\/l5ej7KAwWNA0jyhFKmjF.svg\",\"section_id\":\"[]\",\"phone_no_label\":\"Email Address\",\"email_label\":\"Email Address\",\"address_label\":\"Address\",\"form_right_image\":\"global\\/uploads\\/images\\/y6LyUrtki0rCNAd8MYSw.webp\",\"form_title\":\"Contact Information\",\"form_subtitle\":\"Say something to start a conversation!\",\"form_button_text\":\"Send Message\"}', 'static', 1, 'en', 'contact', '2025-01-13 11:10:19', '2025-12-17 04:04:43'),
(32, 'default', 'About', 'about', '{\"title\":\"About Us\",\"content\":\"<p>\\r\\n        We are a modern digital payment platform built to simplify how individuals and businesses\\r\\n        manage money in a fast-moving, borderless world. Our mission is to make financial\\r\\n        transactions seamless, secure, and accessible for everyone.\\r\\n      <\\/p>\\r\\n\\r\\n      <p>\\r\\n        From instant transfers and multi-wallet support to merchant and agent solutions,\\r\\n        our platform is designed with flexibility and performance at its core.\\r\\n        We combine cutting-edge technology with a user-first approach to deliver\\r\\n        reliable financial services you can trust.\\r\\n      <\\/p>\\r\\n\\r\\n      <p>\\r\\n        Whether you are sending money, managing your business payments, or exploring\\r\\n        new digital opportunities, we are committed to empowering your financial journey\\r\\n        with innovation, transparency, and security.\\r\\n      <\\/p>\\r\\n\\r\\n      <ul>\\r\\n        <li>\\u2714 Secure and scalable payment infrastructure<\\/li>\\r\\n        <li>\\u2714 User, merchant, and agent-friendly solutions<\\/li>\\r\\n        <li>\\u2714 Fast, reliable, and borderless transactions<\\/li>\\r\\n        <li>\\u2714 Built for modern digital economies<\\/li>\\r\\n      <\\/ul>\",\"meta_keywords\":\"About Us\",\"meta_description\":\"About Us\",\"section_id\":\"[\\\"27\\\"]\",\"about_title\":\"Who We Are\",\"button_label\":\"Start Your Journey\",\"button_url\":\"\\/login\",\"button_target\":\"_self\",\"right_image\":\"global\\/uploads\\/images\\/N2ltnepgPhrDWzQlv1hE.webp\",\"mission_title\":\"Our Mission\",\"mission_content\":\"At Qunzo, our mission is to simplify global payments through innovation, transparency, and security \\u2014 empowering individuals and businesses to transact freely without borders or hidden barriers.\",\"vision_title\":\"Our Vision\",\"vision_content\":\"We envision a world where financial freedom is accessible to everyone \\u2014 powered by digital currencies, smart technology, and a trusted ecosystem built for growth.\"}', 'static', 1, 'en', 'about', '2025-01-13 11:10:19', '2025-12-15 12:15:24'),
(33, 'default', 'Merchant', 'merchant', '{\"title\":\"Merchant\",\"section_title\":\"Power Your Business with Qunzo\",\"section_subtitle\":\"Instant payments, real-time tracking, and seamless customer checkout.\",\"button_label\":\"Join as Merchant\",\"button_url\":\"\\/merchant\\/register\",\"button_target\":\"_self\",\"content\":\"<h2>Become a Qunzo Merchant<\\/h2>\\r\\n  <p>\\r\\n    Grow your business with Qunzo by accepting fast, secure, and cashless\\r\\n    payments. As a Qunzo merchant, you can receive payments instantly, manage\\r\\n    transactions easily, and provide a smooth checkout experience for your\\r\\n    customers.\\r\\n  <\\/p>\\r\\n\\r\\n  <h3>What Can You Do as a Merchant?<\\/h3>\\r\\n  <ul>\\r\\n    <li><strong>Accept Digital Payments:<\\/strong> Receive payments via QR code, wallet balance, or digital transfer.<\\/li>\\r\\n    <li><strong>Instant Settlement:<\\/strong> Get paid instantly into your Qunzo merchant wallet.<\\/li>\\r\\n    <li><strong>Transaction History:<\\/strong> Track all sales and payments in real time.<\\/li>\\r\\n    <li><strong>Customer Payments:<\\/strong> Accept secure payments from Qunzo users anytime.<\\/li>\\r\\n  <\\/ul>\\r\\n\\r\\n  <h3>Why Choose Qunzo for Your Business?<\\/h3>\\r\\n  <ul>\\r\\n    <li><strong>Faster Payments:<\\/strong> No waiting, no delays \\u2014 instant confirmation.<\\/li>\\r\\n    <li><strong>Lower Costs:<\\/strong> Reduce cash handling and operational expenses.<\\/li>\\r\\n    <li><strong>Secure Transactions:<\\/strong> Protected by advanced security and fraud prevention.<\\/li>\\r\\n    <li><strong>Merchant Dashboard:<\\/strong> Manage payments, balance, and reports from one place.<\\/li>\\r\\n  <\\/ul>\\r\\n\\r\\n  <h3>How It Works<\\/h3>\\r\\n  <ol>\\r\\n    <li>Register for a merchant account<\\/li>\\r\\n    <li>Complete verification and approval<\\/li>\\r\\n    <li>Start accepting digital payments from customers<\\/li>\\r\\n  <\\/ol>\\r\\n\\r\\n  <h3>Who Can Become a Merchant?<\\/h3>\\r\\n  <p>\\r\\n    Retail stores, restaurants, online shops, service providers, and small\\r\\n    businesses can join Qunzo and go fully digital.\\r\\n  <\\/p>\\r\\n\\r\\n  <p>\\r\\n    <strong>Upgrade your business with Qunzo and accept payments smarter.<\\/strong>\\r\\n  <\\/p>\",\"section_id\":\"[]\"}', 'static', 1, 'en', 'merchant', '2025-01-13 11:10:19', '2025-12-15 06:57:41'),
(34, 'default', 'Agent', 'agent', '{\"title\":\"Agent\",\"section_title\":\"Become a Qunzo Agent\",\"button_label\":\"Join as Agent\",\"button_url\":\"\\/agent\\/register\",\"button_target\":\"_self\",\"content\":\"<h2>Become a Qunzo Agent<\\/h2>\\r\\n  <p>\\r\\n    Join Qunzo\\u2019s trusted agent network and earn by providing essential digital\\r\\n    financial services in your community. As an agent, you help customers\\r\\n    deposit, withdraw, and manage their money securely while growing your income.\\r\\n  <\\/p>\\r\\n\\r\\n  <h3>What Can You Do as an Agent?<\\/h3>\\r\\n  <ul>\\r\\n    <li><strong>Cash In &amp; Cash Out:<\\/strong> Help customers deposit or withdraw funds instantly through their Qunzo wallet.<\\/li>\\r\\n    <li><strong>Wallet Transfers:<\\/strong> Assist users with fast and secure wallet-to-wallet transfers.<\\/li>\\r\\n    <li><strong>Bill Payments:<\\/strong> Enable customers to pay utility bills, mobile recharges, and service fees.<\\/li>\\r\\n    <li><strong>Merchant Support:<\\/strong> Help local merchants accept digital payments and manage transactions.<\\/li>\\r\\n  <\\/ul>\\r\\n\\r\\n  <h3>Why Become a Qunzo Agent?<\\/h3>\\r\\n  <ul>\\r\\n    <li><strong>Earn Commission:<\\/strong> Get paid on every successful transaction.<\\/li>\\r\\n    <li><strong>Flexible Income:<\\/strong> Work on your own schedule and increase earnings.<\\/li>\\r\\n    <li><strong>Secure System:<\\/strong> All transactions are protected with advanced security.<\\/li>\\r\\n    <li><strong>Agent Dashboard:<\\/strong> Track balance, earnings, and transactions easily.<\\/li>\\r\\n  <\\/ul>\\r\\n\\r\\n  <h3>How It Works<\\/h3>\\r\\n  <ol>\\r\\n    <li>Apply for an agent account<\\/li>\\r\\n    <li>Complete verification and approval<\\/li>\\r\\n    <li>Start serving customers and earning commissions<\\/li>\\r\\n  <\\/ol>\\r\\n\\r\\n  <h3>Who Can Become an Agent?<\\/h3>\\r\\n  <p>\\r\\n    Shop owners, entrepreneurs, mobile recharge points, and small business\\r\\n    owners can become Qunzo agents and offer trusted financial services.\\r\\n  <\\/p>\\r\\n\\r\\n  <p>\\r\\n    <strong>Start your agent journey today and grow with Qunzo.<\\/strong>\\r\\n  <\\/p>\",\"section_id\":\"[]\",\"widget_title\":\"Start Earning as an Agent Today!\",\"widget_button_label\":\"Login As Agent\",\"widget_button_url\":\"\\/agent\\/login\",\"widget_button_target\":\"_self\",\"section_subtitle\":\"Join Qunzo\\u2019s trusted agent network and earn by providing essential digital financial services in your community. As an agent, you help customers deposit, withdraw, and manage their money securely \\u2014 while growing your own income.\"}', 'static', 1, 'en', 'agent', '2025-01-13 11:10:19', '2025-12-15 06:53:57'),
(37, 'default', 'How It Works', 'how-it-works', '{\"meta_keywords\":\"How It Works\",\"meta_description\":\"How It Works\",\"section_id\":\"[\\\"35\\\"]\",\"content\":\"\",\"title\":\"How It Works\"}', 'static', 1, 'en', 'how-it-works', '2025-04-27 10:13:11', '2025-12-15 06:09:36'),
(38, 'default', 'Custom Page', 'custom-page', '{\"section_id\":\"[]\",\"meta_keywords\":\"\",\"meta_description\":\"\",\"content\":\"<h1>HELLO,<\\/h1>\\r\\n\\r\\n<p><br><i><b>This is test description<\\/b><\\/i><\\/p>\"}', 'dynamic', 1, 'en', 'custom-page', '2025-12-15 09:56:13', '2025-12-15 09:56:53');
INSERT INTO `testimonials` (`id`, `name`, `designation`, `picture`, `message`, `created_at`, `updated_at`) VALUES
(2, 'Sarah Ahmed', 'Business Owner', 'global/uploads/testimonials/J5n4kkxIjW54grrY2zuH.png', 'Qunzo App makes digital payments unbelievably simple. I can transfer money, pay bills, and withdraw anytime without any hassle.', '2025-12-09 06:51:06', '2025-12-09 06:57:44'),
(3, 'Jonathan Lee', 'Software Engineer', 'global/uploads/testimonials/XRDTdNHbVPcQ5fBpV42U.png', 'The app is fast, secure, and super reliable. Qunzo has become my go-to solution for managing daily financial transactions.', '2025-12-09 06:51:06', '2025-12-09 06:57:57'),
(4, 'Maria Gomez', 'Freelancer', 'global/uploads/testimonials/AOJiM8VoSLzimiowA7O7.png', 'I love how smooth everything works in Qunzo . From sending money to merchants to checking my wallet — everything is instant.', '2025-12-09 06:51:06', '2025-12-09 06:58:14'),
(5, 'David Khan', 'Agency Manager', 'global/uploads/testimonials/IIzOf1Y1LLx9GAivIobH.png', 'Qunzo App helped my business go fully digital. Accepting payments and managing customers is now easier than ever.', '2025-12-09 06:51:06', '2025-12-09 06:58:30'),
(6, 'Emily Carter', 'Marketing Specialist', 'global/uploads/testimonials/AETr79KucoI9kwZBbGLa.png', 'The user interface is clean and easy to understand. Even first-time users can handle transactions effortlessly with Qunzo.', '2025-12-09 06:51:06', '2025-12-09 06:58:43');
