

-- Bill Payment 

CREATE TABLE `bills` (
  `id` bigint UNSIGNED NOT NULL,
  `bill_service_id` bigint UNSIGNED NOT NULL,
  `user_id` bigint UNSIGNED NOT NULL,
  `data` json NOT NULL,
  `response_data` text COLLATE utf8mb4_unicode_ci,
  `amount` decimal(10,2) NOT NULL,
  `charge` decimal(10,2) NOT NULL,
  `status` enum('pending','completed','return') COLLATE utf8mb4_unicode_ci NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE `bill_services` (
  `id` bigint UNSIGNED NOT NULL,
  `api_id` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'service id from api',
  `code` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `method` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `currency` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `country` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `country_code` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `provider_code` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'flutterwave, bloc etc',
  `type` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `label` json NOT NULL,
  `data` json NOT NULL,
  `amount` int NOT NULL DEFAULT '0',
  `min_amount` int NOT NULL DEFAULT '0',
  `max_amount` int NOT NULL DEFAULT '0',
  `charge` double NOT NULL DEFAULT '0',
  `charge_type` enum('fixed','percentage','flexible','range') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'fixed',
  `status` tinyint(1) NOT NULL DEFAULT '0',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;



-- Passcode

ALTER TABLE `users` ADD COLUMN `passcode` TINYINT(1) NOT NULL DEFAULT 0 AFTER `balance`;


